import type { QueryResult } from '@dynatrace-sdk/client-query';
import type { TypedQueryResult } from '@dynatrace-sdk/react-hooks';

/** @internal */
export const _getMetadataMetricsUnitForFieldName = (
  metadata: QueryResult['metadata'] | TypedQueryResult['metadata'] | undefined,
  fieldName: string,
) => metadata?.metrics?.find((metric) => fieldName === metric.fieldName)?.unit;
